package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVFormatTest {

    @Test
    void testGetSkipHeaderRecord_DefaultFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set skipHeaderRecord to false for testing if needed
        CSVFormat modifiedFormat = setSkipHeaderRecord(format, false);
        assertFalse(modifiedFormat.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_CustomTrue() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(true);
        // Use reflection to confirm the field is true
        CSVFormat modifiedFormat = setSkipHeaderRecord(format, true);
        assertTrue(modifiedFormat.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_CustomFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(false);
        // Use reflection to confirm the field is false
        CSVFormat modifiedFormat = setSkipHeaderRecord(format, false);
        assertFalse(modifiedFormat.getSkipHeaderRecord());
    }

    private CSVFormat setSkipHeaderRecord(CSVFormat format, boolean value) throws Exception {
        // Because CSVFormat is immutable and fields are final, we cannot just set the field value.
        // Instead, create a new CSVFormat instance with the same parameters but different skipHeaderRecord.
        // Use reflection to get all fields and invoke constructor with changed skipHeaderRecord.

        Class<CSVFormat> clazz = CSVFormat.class;
        Field[] fields = clazz.getDeclaredFields();

        // Collect all parameters needed for constructor
        char delimiter = getFieldValue(format, "delimiter");
        Character quoteChar = getFieldValue(format, "quoteChar");
        Object quotePolicy = getFieldValue(format, "quotePolicy");
        Character commentStart = getFieldValue(format, "commentStart");
        Character escape = getFieldValue(format, "escape");
        boolean ignoreSurroundingSpaces = getFieldValue(format, "ignoreSurroundingSpaces");
        boolean ignoreEmptyLines = getFieldValue(format, "ignoreEmptyLines");
        String recordSeparator = getFieldValue(format, "recordSeparator");
        String nullString = getFieldValue(format, "nullString");
        String[] header = getFieldValue(format, "header");

        // Find the private constructor
        // Constructor signature:
        // CSVFormat(char delimiter, Character quoteChar, Quote quotePolicy, Character commentStart,
        //           Character escape, boolean ignoreSurroundingSpaces, boolean ignoreEmptyLines,
        //           String recordSeparator, String nullString, String[] header, boolean skipHeaderRecord)

        java.lang.reflect.Constructor<CSVFormat> constructor = clazz.getDeclaredConstructor(
                char.class,
                Character.class,
                Class.forName("org.apache.commons.csv.Quote"),
                Character.class,
                Character.class,
                boolean.class,
                boolean.class,
                String.class,
                String.class,
                String[].class,
                boolean.class
        );
        constructor.setAccessible(true);

        return constructor.newInstance(
                delimiter,
                quoteChar,
                quotePolicy,
                commentStart,
                escape,
                ignoreSurroundingSpaces,
                ignoreEmptyLines,
                recordSeparator,
                nullString,
                header,
                value
        );
    }

    @SuppressWarnings("unchecked")
    private <T> T getFieldValue(CSVFormat format, String fieldName) throws Exception {
        Field field = CSVFormat.class.getDeclaredField(fieldName);
        field.setAccessible(true);
        return (T) field.get(format);
    }
}
